// LinkedIn analytics — Spark batch over immutable Parquet on S3
const dailyActive = spark.read.parquet("s3://events/dt=2025-06-01/")
  .filter(col("event") === "login")
  .groupBy("user_id")
  .agg(count("*").as("logins"));
dailyActive.write.mode("overwrite").parquet("s3://metrics/dau/");
